# %% ../nbs/api/metadata.ipynb #inis-parse-creators
def parse_inis_creator(
    creator: dict # Raw INIS creator payload
    ) -> dict | None: # Zotero-compatible creator mapping or `None`
    role = creator.get('role', {}).get('id') or 'author'
    person_or_org = creator.get('person_or_org', {})
    entity_type = person_or_org.get('type')
    name = person_or_org.get('name') or creator.get('name') or ''

    if entity_type == 'organizational':
        return {'creatorType': role, 'name': name} if name else None

    given_name = person_or_org.get('given_name') or creator.get('given_name') or ''
    family_name = person_or_org.get('family_name') or creator.get('family_name') or ''

    if (not given_name or not family_name) and ',' in name:
        family_guess, given_guess = [part.strip() for part in name.split(',', 1)]
        family_name = family_name or family_guess
        given_name = given_name or given_guess

    if given_name and family_name:
        return {
            'creatorType': role,
            'firstName': given_name,
            'lastName': family_name,
        }

    if name:
        return {'creatorType': role, 'name': name}

    return None


def parse_inis_creators(
    creators: list[dict] # Raw INIS creator payloads
    ) -> str: # JSON-encoded list of normalized Zotero-compatible creators
    normalized = []
    for creator in creators:
        parsed = parse_inis_creator(creator)
        if parsed is not None:
            normalized.append(parsed)
    return json.dumps(normalized, ensure_ascii=True)

# %% ../nbs/api/metadata.ipynb #inis-parse-meta
def parse_inis_title(
    item: dict # Raw INIS record payload
    ) -> str: # Parsed title string
    title = item.get('metadata', {}).get('title', '')
    if isinstance(title, dict):
        if isinstance(title.get('en'), str) and title.get('en'):
            return title['en']
        for value in title.values():
            if isinstance(value, str) and value:
                return value
        return ''
    return title or ''


def parse_inis_summary(
    item: dict # Raw INIS record payload
    ) -> str: # Parsed summary string
    summary = item.get('metadata', {}).get('description', '')
    if isinstance(summary, dict):
        if isinstance(summary.get('en'), str) and summary.get('en'):
            return summary['en']
        for value in summary.values():
            if isinstance(value, str) and value:
                return value
        return ''
    return summary or ''


def parse_inis_doi(
    item: dict # Raw INIS record payload
    ) -> str: # DOI string if available
    doi = item.get('pids', {}).get('doi', {})
    if isinstance(doi, dict):
        identifier = doi.get('identifier') or doi.get('id')
        if identifier:
            return identifier
    for identifier in item.get('metadata', {}).get('identifiers', []):
        if identifier.get('scheme') == 'doi':
            return identifier.get('identifier', '')
    return ''


def parse_inis_url(
    item: dict # Raw INIS record payload
    ) -> str: # Best available HTML or API URL
    links = item.get('links', {})
    return links.get('self_html') or links.get('latest_html') or links.get('self', '')

