class INISClient:
    "Retrieve INIS metadata from the InvenioRDM API or from a local mock payload."
    def __init__(self,
                 inis_id:str,     # INIS record identifier (e.g. 'vq0ha-86k24')
                 cfg:Dict         # Full config dict or INIS-specific config dict
                ):
        store_attr()
        self.inis_cfg = self.cfg.get('inis', self.cfg) if isinstance(self.cfg, dict) else {}
        self.api_url = self.inis_cfg.get('api_url', 'https://inis-qa.iaea.org/api/records')
        self.used_mock = False
        self.item = self.getItem(inis_id)

    def exist(self): return self.item != None

    def getItem(self,
                inis_id:str # INIS record identifier
                ) -> Dict: # Raw INIS record payload
        mock_response = self.inis_cfg.get('mock_response')
        if mock_response is not None:
            self.used_mock = True
            return mock_response
        if self.inis_cfg.get('use_mock', True):
            self.used_mock = True
            return self.mock_item(inis_id)
        endpoint = f"{self.api_url.rstrip('/')}/{inis_id}"
        try:
            with urlopen(endpoint) as response:
                return json.loads(response.read().decode('utf-8'))
        except HTTPError as exc:
            if exc.code == 404:
                print(f'Item {inis_id} does not exist in INIS API')
            else:
                print(f'Unable to retrieve INIS item {inis_id}: HTTP {exc.code}')
        except URLError as exc:
            print(f'Unable to retrieve INIS item {inis_id}: {exc.reason}')
        curl_item = self.getItemViaCurl(endpoint)
        if curl_item is not None: return curl_item
        if self.inis_cfg.get('fallback_to_mock', self.inis_cfg.get('use_mock', True)):
            self.used_mock = True
            return self.mock_item(inis_id)
        return None

    def getItemViaCurl(self,
                      endpoint:str # Fully qualified INIS API record URL
                      ) -> Dict | None: # Raw INIS record payload if curl succeeds
        "Fallback to curl for environments where Python TLS transport closes early."
        try:
            response = subprocess.run(
                ['curl.exe', '-sS', '-H', 'Accept: application/json', endpoint],
                capture_output=True,
                text=True,
                encoding='utf-8',
                check=True,
            )
            return json.loads(response.stdout)
        except subprocess.CalledProcessError as exc:
            err = (exc.stderr or '').strip() or repr(exc)
            print(f'Unable to retrieve INIS item via curl: {err}')
        except json.JSONDecodeError as exc:
            print(f'Unable to decode INIS item via curl: {exc}')
        return None

    def mock_item(self,
                  inis_id:str # INIS record identifier
                  ) -> Dict: # Fallback mock record payload
        return {
            'id': inis_id,
            'metadata': {
                'title': f'INIS QA record {inis_id}',
                'description': 'Mock INIS QA record used to keep the metadata callback contract stable during development.',
                'creators': [
                    {
                        'person_or_org': {
                            'type': 'organizational',
                            'name': 'International Atomic Energy Agency'
                        },
                        'role': {'id': 'author'}
                    }
                ],
                'identifiers': [
                    {
                        'identifier': f'10.12345/inis.{inis_id.lower()}',
                        'scheme': 'doi'
                    }
                ]
            },
            'pids': {
                'doi': {
                    'identifier': f'10.12345/inis.{inis_id.lower()}'
                }
            },
            'links': {
                'self': f"{self.api_url.rstrip('/')}/{inis_id}",
                'self_html': f"https://inis-qa.iaea.org/records/{inis_id}"
            }
        }

    def title(self): return parse_inis_title(self.item)
    def summary(self): return parse_inis_summary(self.item)
    def creator_name(self): return parse_inis_creators(self.item.get('metadata', {}).get('creators', []))
    def doi(self): return parse_inis_doi(self.item)
    def url(self): return parse_inis_url(self.item)

    def __repr__(self):
        return json.dumps(self.item, indent=4)

# %% ../nbs/api/metadata.ipynb #13d90fd3
class InisCB(Callback):
    "Populate global attributes from INIS metadata."
    def __init__(self,
                 inis_id:str,  # INIS record identifier to retrieve
                 cfg:Dict      # Full config dict or INIS-specific config dict
                ): store_attr()
    def __call__(self,
                 obj # Object exposing an `attrs` dict to populate
                 ):
        item = INISClient(self.inis_id, self.cfg)
        if item.exist():
            obj.attrs['id'] = item.item.get('id', self.inis_id)
            for attr in ['title', 'summary', 'creator_name']:
                obj.attrs[attr] = getattr(item, attr)()
            if item.doi(): obj.attrs['references'] = item.doi()
            if item.url(): obj.attrs['metadata_link'] = item.url()

